namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // --- CalculateTotal: DataRow for simple compile-time constants ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0, 50.00, DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 10, 0.20, 0.00, DisplayName = "Zero price returns zero")]
    [DataRow(99.99, 0, 0.15, 0.00, DisplayName = "Zero quantity returns zero")]
    [DataRow(100.00, 2, 1.0, 400.00, DisplayName = "Max tax rate (100%)")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expectedTotal)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expectedTotal, result);
    }

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, DisplayName = "Negative unit price throws")]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity throws")]
    public void CalculateTotal_WithNegativeInputs_ThrowsArgumentOutOfRangeException(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, 1, -0.01, DisplayName = "Tax rate below zero")]
    [DataRow(10.00, 1, 1.01, DisplayName = "Tax rate above one")]
    public void CalculateTotal_WithInvalidTaxRate_ThrowsArgumentOutOfRangeException(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    // --- ApplyDiscount: DynamicData for richer test cases ---

    public static IEnumerable<object[]> DiscountTestCases
    {
        get
        {
            yield return new object[] { 100.00m, 0m, 100.00m, "No discount" };
            yield return new object[] { 100.00m, 10m, 90.00m, "10% off" };
            yield return new object[] { 100.00m, 50m, 50.00m, "Half price" };
            yield return new object[] { 100.00m, 100m, 0.00m, "Full discount" };
            yield return new object[] { 49.99m, 25m, 37.4925m, "Fractional result" };
            yield return new object[] { 200.00m, 33.33m, 133.34m, "Repeating decimal percent" };
        }
    }

    [TestMethod]
    [DynamicData(nameof(DiscountTestCases))]
    public void ApplyDiscount_WithValidInputs_ReturnsExpectedPrice(
        decimal price, decimal discountPercent, decimal expectedPrice, string scenario)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expectedPrice, result, $"Failed for scenario: {scenario}");
    }

    public static IEnumerable<object[]> InvalidDiscountTestCases
    {
        get
        {
            yield return new object[] { 100.00m, -1m, "Negative discount" };
            yield return new object[] { 100.00m, 100.01m, "Discount exceeds 100%" };
            yield return new object[] { 50.00m, 200m, "Absurd discount" };
        }
    }

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountTestCases))]
    public void ApplyDiscount_WithInvalidPercent_ThrowsArgumentOutOfRangeException(
        decimal price, decimal discountPercent, string scenario)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent),
            $"Expected exception for scenario: {scenario}");
    }
}

